VALUES
  ('disabled-8b44517b-moex-00014', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '依憲法訴訟法規定，有關憲法法庭判決宣告法規範定期失效相關之敘述， 下列何者正確？', '["因舊法規尚未失效，故各法院仍應依舊法判決，不得停止訴訟", "判決法規範定期失效者，各法院應依職權裁定停止審理程序", "審理原因案件之法院，原則上不受定期失效期限之拘束", "審理原因案件之法院，除判決主文另有諭知外，應依舊法為判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00015', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '憲法明文規定人民身體之自由應予保障，下列敘述何者錯誤？', '["人民身體自由係人民在小範圍內動靜坐臥的身體移動自由", "用以抵抗國家公權力及他人不合法的限制人民身體移動的自由", "人民身體自由享有充分保障，乃行使其憲法上所保障其他權利之前提", "強制入院治療係對於人民身體自由之限制，應符合憲法第 8 條及第 23 條規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00016', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '依據憲法本文之規定，監察院提出糾正案之對象為何？', '["行政院及其有關部會", "立法院", "司法院", "考試院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00017', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '依憲法法庭判決，關於誹謗罪與言論自由之保障，下列敘述何者錯誤？', '["人民之名譽權與言論自由，應受憲法無分軒輊之保障，國家原則上均應 給予最大限度之保障", "表意人未提供佐證依據之事實性言論，縱內容涉及公共事務，對公益論 辯貢獻度仍不高，該言論所指述者之名譽權應受較高程度之保障", "涉及私德之誹謗言論，與公共利益無關時，表意人之言論自由應完全退 讓於被指述者名譽權與隱私權之保護", "表意人於社群媒體與自媒體上所為誹謗言論，與一般人日常生活中以言 詞所為口耳間傳播之誹謗言論，在事前查證程序之要求上，並無不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00018', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '有關憲法保障之隱私權，下列敘述何者錯誤？', '["隱私權保障範圍包括個人生活私密領域免於他人侵擾之權利", "基於人性尊嚴與個人主體性之維護及人格發展之完整，隱私權為不可或 缺之基本權利", "隱私權保障範圍包括個人資料之自主控制權利", "就資訊隱私權而言，保障人民決定是否揭露其個人資料，但不包括對其 個人資料記載錯誤之更正權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00019', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '依司法院大法官解釋，下列那一基本權利非以憲法第22條規定為依據？', '["資訊隱私權", "原住民（族）身分認同權", "人民收養子女之自由", "通訊傳播自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00020', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '依司法院釋字第 756 號，有關監獄管理機關對受刑人秘密通訊自由之限 制，下列敘述何者錯誤？', '["監獄長官以儀器檢查書信之內容物，不必然影響通訊內容之秘密性", "監獄長官不區分書信種類，一律閱讀受刑人之書信，係屬違憲侵害其秘 密通訊自由之行為", "監獄長官以維護監獄紀律（例如監所之名譽）為由，要求受刑人刪除書 信之內容，非屬限制其秘密通訊自由之正當目的", "受刑人書信之內容遭刪除者，應保留書信全文影本，嗣受刑人出獄時發 還之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00021', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋，關於行政院院長，下列敘述何者 錯誤？', '["總統發布行政院院長的免職令，無須行政院院長副署", "有關行政院院長的任期，並無明文規定", "立法院對行政院院長所提出的不信任案如未獲通過，不得對同一行政院 院長再提不信任案", "總統藉由其任命的行政院院長，變更先前存在，與其政見未洽之施政方 針或政策，屬政黨政治常態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00022', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '憲法第 73 條規定，立法委員在院內所為之言論及表決，對院外不負責 任。依司法院釋字第435號，關於立法委員之言論免責權，下列敘述何者 錯誤？', '["司法機關為維護社會秩序及被害人權益，對於立法委員行為是否逾越免 責保障之範圍，於必要時得依法行使偵審之權限", "舉凡在院會或委員會之發言、質詢、提案、表決以及與此直接相關之附 隨行為，均屬應予保障之事項", "與行使職權無關之行為，諸如蓄意之肢體動作等，顯然不符意見表達之 適當情節致侵害他人法益者，不在保障之列", "言論免責權為憲法賦予立法委員之例外特權，故其保障範圍應作最小程 度之嚴格界定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00023', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-decd973b', 'sub-disabled-8b44517b-03', NULL, 'single_choice', '下列何者之自治權，受憲法保障？', '["鄉（鎮、市）", "獨立行政機關", "大學", "祭祀公業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:19+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL)
